<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function eeError(m){$('.isi_warning_delete').text(m||'Employee Education gagal diproses.');$('.error_data_delete').fadeIn();}
function eeFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),education_level:$('#filter_education_level').val(),education_type:$('#filter_education_type').val(),verified_status:$('#filter_verified_status').val(),highest_education:$('#filter_highest_education').val(),status:$('#filter_status').val(),keyword:$('#filter_keyword').val()};}
function eeSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function eeReset(title){$('#form_employee_education')[0].reset();$('#ee_id').val('');$('#employee_id,#verified_by_employee_id').val(null).trigger('change');$('#education_level').val('S1').trigger('change');$('#education_type').val('FORMAL').trigger('change');$('#highest_education,#relevant_to_position').val('N').trigger('change');$('#verified_status').val('PENDING').trigger('change');$('#status').val('ACTIVE').trigger('change');$('#country').val('ID');$('#effective_from').val('<?=$defaultFrom;?>');$('#effective_to').val('<?=$defaultTo;?>');$('#modal_employee_education .modal-title').text(title||'Create Education');}
function eeAjax(s,p){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:$('#modal_employee_education'),ajax:{url:'<?=base_admin();?>modul/employee_education/employee_education_action.php?act=employee_search',type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.ee-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_education_level,#filter_education_type,#filter_verified_status,#filter_highest_education,#filter_status,#education_level,#education_type,#highest_education,#relevant_to_position,#verified_status,#status').select2({width:'100%',allowClear:true});eeAjax('#employee_id','Pilih Employee...');eeAjax('#verified_by_employee_id','Pilih Verifier...');}
var dt=$('#dtb_employee_education').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'150px',targets:1}],ajax:{url:'<?=base_admin();?>modul/employee_education/employee_education_data.php',type:'post',data:function(d){$.extend(d,eeFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_highest').text(k.highest||0);$('#kpi_verified').text(k.verified||0);$('#kpi_pending').text(k.pending||0);return j.data||[];},error:function(x){console.log(x.responseText);eeError('Data Employee Education gagal dimuat.');}}});
$('#btn_open_ee').click(function(){eeReset('Create Education');$('#modal_employee_education').modal({backdrop:'static',keyboard:false});});$('#btn_filter_ee').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_ee').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_education_level,#filter_education_type,#filter_verified_status,#filter_highest_education,#filter_status').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_ee').click(function(){window.location='<?=base_admin();?>modul/employee_education/employee_education_action.php?act=export&'+$.param(eeFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#education_no,#country').on('keyup change',function(){this.value=this.value.toUpperCase();});
$('#form_employee_education').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/employee_education/employee_education_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Education');if(r.status==='good'){$('#modal_employee_education').modal('hide');dt.draw(false);Swal.fire('Saved','Employee Education berhasil disimpan.','success');}else eeError(r.error_message);},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Education');eeError(x.responseText);});});
$(document).on('click','.btn-ee-detail',function(){$.post('<?=base_admin();?>modul/employee_education/employee_education_action.php?act=detail',{id:$(this).data('id')},function(h){$('#ee_detail_body').html(h);$('#modal_ee_detail').modal('show');});});
$(document).on('click','.btn-ee-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/employee_education/employee_education_action.php?act=get',{id:id},function(r){if(r.status!=='good'){eeError(r.error_message);return;}eeReset('Edit Education');var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&!['employee_id','verified_by_employee_id'].includes(k))el.val(h[k]);});$('#ee_id').val(h.id);eeSet('#employee_id',h.employee_id,h.employee_text);eeSet('#verified_by_employee_id',h.verified_by_employee_id,h.verified_by_text);$('#education_level,#education_type,#highest_education,#relevant_to_position,#verified_status,#status').trigger('change');$('#modal_employee_education').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-ee-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/employee_education/employee_education_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else eeError(r.error_message);},'json');});
$(document).on('click','.btn-ee-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/employee_education/employee_education_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else eeError(r.error_message);},'json').fail(function(x){eeError(x.responseText);});});});
});
</script>
